class Solution {
public:
    int findMinimumOperations(string s1, string s2, string s3) {
        int i = s1.size() - 1, j = s2.size() - 1, k = s3.size() - 1;
        int operations = 0;
        while (i >= 0 && j >= 0 && k >= 0) {
            if (s1[i] != s2[j] || s2[j] != s3[k]) {
                return -1;
            }
            operations++;
            i--; j--; k--;
        }
        return i + j + k;
    }
};
